import { execution } from '@dynatrace-sdk/automation-utils';
import { entitiesClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    // Query entity details with relationships
    const response = await entitiesClient.getEntity({
      entityId: input.entityId,
      from: Date.now() - 3600000, // Last hour
      to: Date.now(),
      includeRelationships: true
    });

    const entity = response.entities[0];
    let relationships = [];

    if (entity.toRelationships) {
      relationships = relationships.concat(entity.toRelationships);
    }
    if (entity.fromRelationships) {
      relationships = relationships.concat(entity.fromRelationships);
    }

    // Filter by relationship type if specified
    if (input.relationshipType) {
      relationships = relationships.filter(r => r.type === input.relationshipType);
    }

    console.log(`Found ${relationships.length} relationships for ${input.entityId}`);

    return {
      entityId: input.entityId,
      entityName: entity.displayName,
      relationshipCount: relationships.length,
      relationships: relationships
    };
  } catch (error) {
    console.error('Error querying topology:', error);
    throw new Error(`Failed to query topology: ${error}`);
  }
}
